require 'rails_helper'

RSpec.describe Api::V1::SignaturesController, type: :request do
  include_context 'rpdoc'

  before(:each) do |example|
    example.metadata[:rpdoc_action_key] = 'images_to_mp4'
    example.metadata[:rpdoc_action_name] = 'images to mp4 base64'
    example.metadata[:rpdoc_example_folders] = ['v1', 'signatures']
  end

  describe '#images to mp4 base64' do
    before(:each) do
      @member = mock_member(:member_me)
      mock_service(SignatureVideo::ImageConvertMp4Base64, result: "mp4 base64 encoded string")
      @path = "/api/v1/signatures/images_to_mp4_base64"
      @headers = {
        'Content-Type' => 'application/json',
      }
      @params = {
        "base64_images": [
          "data:image/png;base64,",
          "data:image/png;base64,",
          "data:image/png;base64,"
        ]
      }
    end

    it 'should return 200 and create a images_to_mp4_base64 in normal sign' , rpdoc_example_key: 200, rpdoc_example_name: 'create by token' do
      @headers['Authorization'] = 'Bearer {{rabbit_token}}'
      post @path, params: @params.to_json, headers: @headers
      expect(response).to have_http_status(200)
    end

    it 'should return 200 and create a images_to_mp4_base64 in quick sign' , rpdoc_example_key: 200_1, rpdoc_example_name: 'create by code' do
      task = FactoryBot.create(:quick_sign_task)
      not_kdan_stage = task.processing_stages[0]
      @params[:code] = task.original_file.preview_code(not_kdan_stage)
      post @path, params: @params.to_json, headers: @headers
      expect(response).to have_http_status(200)
    end

    it 'should return 200 and create a images_to_mp4_base64 in form sign' , rpdoc_example_key: 200_2, rpdoc_example_name: 'create by form token' do
      form = FactoryBot.create(:public_form, owner: @member)
      form_task = mock_form_task_read(form)
      @params[:form_token] = form_task.form_token
      post @path, params: @params.to_json, headers: @headers
      expect(response).to have_http_status(200)
    end
  end
end
